apiVersion: v1
kind: ConfigMap
metadata:
  name: {{ .Values.name | default "ai-analytics-graphql" }}-config
  labels:
    app: {{ .Values.name | default "ai-analytics-graphql" }}
  annotations:
    harness.io/skip-versioning: "true"
data:
  # S3 Configuration
  CSV_EXPORT_S3_ENABLED: {{ ( .Values.csv.export.s3.enabled | default "true" ) | quote }}
  CSV_EXPORT_S3_BUCKET_NAME: {{ ( .Values.csv.export.s3.bucketName ) | quote }}
  CSV_EXPORT_S3_REGION: {{ ( .Values.csv.export.s3.region | default "us-east-1" ) | quote }}
  CSV_EXPORT_S3_FOLDER_PREFIX: {{ ( .Values.csv.export.s3.folderPrefix | default "tlm-reports" ) | quote }}
  CSV_EXPORT_S3_USE_IAM_ROLE: {{ ( .Values.csv.export.s3.useIAMRole | default "true" ) | quote }}
  # CSV Export Configuration
  CSV_EXPORT_ENABLED: {{ ( .Values.csv.export.enabled | default "true" ) | quote }}
  CSV_EXPORT_LIMIT: {{ ( .Values.csv.export.limit | default "10000" ) | quote }}
  CSV_EXPORT_BATCH_SIZE: {{ ( .Values.csv.export.batchSize | default "1000" ) | quote }}
  CSV_EXPORT_THRESHOLD: {{ ( .Values.csv.export.threshold | default "1000" ) | quote }}
  CSV_EXPORT_MAX_CONCURRENT_CALLS: {{ ( .Values.csv.export.maxConcurrentCalls | default "10" ) | quote }}
  CSV_EXPORT_TIMEOUT_SECONDS: {{ ( .Values.csv.export.timeoutSeconds | default "300" ) | quote }}

  # Parallel Processing Configuration
  PARALLEL_PROCESSING_ENABLED: {{ ( .Values.parallelProcessing.enabled | default "true" ) | quote }}
  PARALLEL_PROCESSING_MAX_CONCURRENT_CALLS: {{ ( .Values.parallelProcessing.maxConcurrentCalls | default "30" ) | quote }}
  PARALLEL_PROCESSING_BATCH_SIZE: {{ ( .Values.parallelProcessing.batchSize | default "500" ) | quote }}
  PARALLEL_PROCESSING_SINGLE_CALL_THRESHOLD: {{ ( .Values.parallelProcessing.singleCallThreshold | default "500" ) | quote }}
  PARALLEL_PROCESSING_PARTIAL_FAILURE_ALLOWED: {{ ( .Values.parallelProcessing.partialFailureAllowed | default "true" ) | quote }}
  PARALLEL_PROCESSING_TIMEOUT_SECONDS: {{ ( .Values.parallelProcessing.timeoutSeconds | default "300" ) | quote }}

  # REST API Configuration
  REST_API_BASE_URL: {{ ( .Values.restApi.baseUrl | default "https://stage.one.digicert.com/mpki/api/v1" ) | quote }}
  REST_API_TIMEOUT: {{ ( .Values.restApi.timeout | default "120000" ) | quote }}

  # AWS Parameter Store Configuration
  AWS_PARAMETERSTORE_ENABLED: {{ ( .Values.aws.parameterStore.enabled | default "true" ) | quote }}
  AWS_PARAMETERSTORE_REGION: {{ ( .Values.aws.region | default "us-east-1" ) | quote }}
  AWS_PARAMETERSTORE_USE_IAM_ROLE: {{ ( .Values.aws.parameterStore.awsParameterStoreUseIAMRole | default "true" ) | quote }}
  AWS_PARAMETERSTORE_PARAMETERS: {{ ( .Values.aws.parameterStore.awsParameterStoreParameters | default "knowledge_base_instructions_tlm,knowledge_base_id_tlm,agent_id_nlp_to_api_tlm,agent_alias_id_nlp_to_api_tlm,digicert_base_url" ) | quote }}

  # Parameter Store Fallback Values
  PARAMETER_FALLBACK_DIGICERT_BASE_URL: {{ ( .Values.restApi.parameterFallback | default "https://stage.one.digicert.com/mpki/api/v1" ) | quote }}
  PARAMETER_FALLBACK_KNOWLEDGE_BASE_INSTRUCTIONS_TLM: ""
  PARAMETER_FALLBACK_KNOWLEDGE_BASE_ID_TLM: ""
  PARAMETER_FALLBACK_AGENT_ID_NLP_TO_API_TLM: ""
  PARAMETER_FALLBACK_AGENT_ALIAS_ID_NLP_TO_API_TLM: ""

  # Application Configuration
  SPRING_APPLICATION_NAME: {{ ( .Values.name | default "ai-analytics-graphql" ) | quote }}
  SPRING_CODEC_MAX_IN_MEMORY_SIZE: "52428800"
  SPRING_WEBFLUX_MULTIPART_MAX_IN_MEMORY_SIZE: "52428800"
  SPRING_MVC_ASYNC_REQUEST_TIMEOUT: "180000"

  # Tomcat Server Configuration
  SERVER_TOMCAT_CONNECTION_TIMEOUT: "180000"
  SERVER_TOMCAT_KEEP_ALIVE_TIMEOUT: "180000"

  # Logging Configuration
  LOGGING_LEVEL_COM_DIGICERT_CERTIFICATE: "DEBUG"
  LOGGING_LEVEL_COM_DIGICERT_GRAPHQLPOC: "DEBUG"
  LOGGING_PATTERN_CONSOLE: "%d{yyyy-MM-dd HH:mm:ss} - %msg%n"

  # New Relic Configuration
  NEW_RELIC_APP_NAME: {{ ( .Values.newRelicAppName | default "ai-analytics-graphql" ) | quote }}
  NEW_RELIC_ENVIRONMENT: {{ ( .Values.newRelicEnvironment | default "dev" ) | quote }}
  NEW_RELIC_LOG_LEVEL: {{ ( .Values.newRelicLogLevel | default "info" ) | quote }}

package com.digicert.certificate;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import jakarta.annotation.PostConstruct;
import reactor.core.publisher.Hooks;



@SpringBootApplication
public class GraphqlPocApplication {

    @PostConstruct
    public void init() {
        Hooks.enableAutomaticContextPropagation();
    }


    public static void main(String[] args) {
        SpringApplication.run(GraphqlPocApplication.class, (String[])args);
    }
}

