    public Mono<CertificateSearchResult> searchCertificates(
            String requestId, String cookie, Integer offset, Integer limit, List<String> sort, 
            String accountId, String businessUnitId, String businessUnitName, String profileId, 
            String seatId, String seatTypeId, String serialNumber, String validFrom, String validTo, 
            String commonName, String aki, String issuingCaId, String issuingCaName, 
            String issuingCaSerialNumber, String status, String thumbprint, String enrollmentId, 
            String customAttributes, String certOwners, String extendedKeyUsage, String icaId, 
            Integer keyLength, String signingAlgorithm, String organizationName, String caVendor, 
            Boolean escrow, String sans, String source, CertificateIssueType certIssue) {

        logger.debug("Sending request to DigiCert with Cookie: {} - requestId: {}", 
                (Object)LogSanitizer.sanitize(cookie != null ? cookie.replaceAll("dcone\\.access\\.token=[^;]+", "dcone.access.token=***") : "null"), 
                (Object)LogSanitizer.sanitize(requestId));

        return this.webClient.get().uri(uriBuilder -> {
            uriBuilder.path("/certificate-search");
            if (offset != null) {
                uriBuilder.queryParam("offset", new Object[]{offset});
            }
            if (limit != null) {
                uriBuilder.queryParam("limit", new Object[]{limit});
            }
            if (sort != null && !sort.isEmpty()) {
                uriBuilder.queryParam("sort", new Object[]{String.join((CharSequence)",", sort)});
            }
            if (accountId != null) {
                uriBuilder.queryParam("account_id", new Object[]{accountId});
            }
            if (businessUnitId != null) {
                uriBuilder.queryParam("business_unit_id", new Object[]{businessUnitId});
            }
            if (businessUnitName != null) {
                uriBuilder.queryParam("business_unit_name", new Object[]{businessUnitName});
            }
            if (profileId != null) {
                uriBuilder.queryParam("profile_id", new Object[]{profileId});
            }
            if (seatId != null) {
                uriBuilder.queryParam("seat_id", new Object[]{seatId});
            }
            if (seatTypeId != null) {
                uriBuilder.queryParam("seat_type_id", new Object[]{seatTypeId});
            }
            if (serialNumber != null) {
                uriBuilder.queryParam("serial_number", new Object[]{serialNumber});
            }
            if (validFrom != null) {
                uriBuilder.queryParam("valid_from", new Object[]{validFrom});
            }
            if (validTo != null) {
                uriBuilder.queryParam("valid_to", new Object[]{validTo});
            }
            if (commonName != null) {
                uriBuilder.queryParam("common_name", new Object[]{commonName});
            }
            if (aki != null) {
                uriBuilder.queryParam("aki", new Object[]{aki});
            }
            if (issuingCaId != null) {
                uriBuilder.queryParam("issuing_ca_id", new Object[]{issuingCaId});
            }
            if (issuingCaName != null) {
                uriBuilder.queryParam("issuing_ca_name", new Object[]{issuingCaName});
            }
            if (issuingCaSerialNumber != null) {
                uriBuilder.queryParam("issuing_ca_serial_number", new Object[]{issuingCaSerialNumber});
            }
            if (status != null) {
                uriBuilder.queryParam("status", new Object[]{status.toLowerCase()});
