            if (thumbprint != null) {
                uriBuilder.queryParam("thumbprint", new Object[]{thumbprint});
            }
            if (enrollmentId != null) {
                uriBuilder.queryParam("enrollment_id", new Object[]{enrollmentId});
            }
            if (customAttributes != null) {
                uriBuilder.queryParam("custom_attributes", new Object[]{customAttributes});
            }
            if (certOwners != null) {
                uriBuilder.queryParam("cert_owners", new Object[]{certOwners});
            }
            if (extendedKeyUsage != null) {
                uriBuilder.queryParam("extendedKeyUsage", new Object[]{extendedKeyUsage.trim()});
            }
