            }
            if (signingAlgorithm != null) {
                uriBuilder.queryParam("signing_algorithm", new Object[]{signingAlgorithm});
            }
            if (organizationName != null) {
                uriBuilder.queryParam("organizationName", new Object[]{organizationName});
            }
            if (caVendor != null) {
                uriBuilder.queryParam("caVendor", new Object[]{caVendor});
            }
            if (escrow != null) {
                uriBuilder.queryParam("escrow", new Object[]{escrow});
            }
            if (sans != null) {
                uriBuilder.queryParam("sans", new Object[]{sans});
            }
            if (source != null) {
                uriBuilder.queryParam("source", new Object[]{source});
            }
            if (certIssue != null) {
                uriBuilder.queryParam("cert_issue", new Object[]{certIssue.toApiValue()});
            }
            return uriBuilder.build(new Object[0]);
        }).header("Accept", new String[]{"application/json"})
          .header("Cookie", new String[]{cookie})
          .retrieve()
          .onStatus(httpStatus -> httpStatus.value() == 401, response -> {
              int statusCode = response.statusCode().value();

              // Enhanced MDC logging
              MDC.put("digicert.statusCode", String.valueOf(statusCode));
              MDC.put("digicert.endpoint", "/certificate-search");
              MDC.put("error.category", "external-api-error");

              logger.warn("DigiCert API returned 401 - cookies have expired - requestId: {}", (Object)LogSanitizer.sanitize(requestId));

              // Clear MDC
              MDC.remove("digicert.statusCode");
              MDC.remove("digicert.endpoint");
              MDC.remove("error.category");

              // Report to New Relic as custom event
              Map<String, Object> eventAttributes = new HashMap<>();
              eventAttributes.put("service", "digicert-api");
              eventAttributes.put("endpoint", "/certificate-search");
              eventAttributes.put("statusCode", statusCode);
              eventAttributes.put("requestId", requestId);
              eventAttributes.put("errorType", "CLIENT_ERROR");
              eventAttributes.put("errorSubType", "AUTHENTICATION_ERROR");
              if (accountId != null) {
                  eventAttributes.put("accountId", accountId);
              }

              NewRelic.getAgent().getInsights().recordCustomEvent("DigiCertApiError", eventAttributes);

              // Report to New Relic Errors Inbox with custom attributes
              Map<String, String> errorParams = new HashMap<>();
              errorParams.put("digicert.statusCode", String.valueOf(statusCode));
              errorParams.put("digicert.endpoint", "/certificate-search");
              errorParams.put("digicert.errorType", "CLIENT_ERROR");
              errorParams.put("digicert.errorSubType", "AUTHENTICATION_ERROR");
              errorParams.put("digicert.requestId", requestId);
              if (accountId != null) {
                  errorParams.put("digicert.accountId", accountId);
              }

              // Capture response body if available
              return response.bodyToMono(String.class)
                  .defaultIfEmpty("")
                  .flatMap(body -> {
                      if (body != null && !body.isEmpty()) {
                          logger.debug("DigiCert API 401 response body: {}", LogSanitizer.sanitize(body));
                      }
                      AuthenticationException exception = AuthenticationException.expiredCookies();
                      NewRelic.noticeError(exception, errorParams);
                      return Mono.error((Throwable)exception);
                  });
          })
          .onStatus(httpStatus -> httpStatus.value() == 400, response -> {
              int statusCode = response.statusCode().value();

              // Enhanced MDC logging
              MDC.put("digicert.statusCode", String.valueOf(statusCode));
              MDC.put("digicert.endpoint", "/certificate-search");
              MDC.put("error.category", "external-api-error");

              logger.warn("DigiCert API returned 400 Bad Request - requestId: {}", (Object)LogSanitizer.sanitize(requestId));

              // Clear MDC
              MDC.remove("digicert.statusCode");
              MDC.remove("digicert.endpoint");
              MDC.remove("error.category");

              // Report to New Relic as custom event
              Map<String, Object> eventAttributes = new HashMap<>();
              eventAttributes.put("service", "digicert-api");
              eventAttributes.put("endpoint", "/certificate-search");
