package com.digicert.certificate.config;

import java.util.concurrent.Executor;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.scheduling.annotation.EnableAsync;
import org.springframework.scheduling.concurrent.ThreadPoolTaskExecutor;

@Configuration
@EnableAsync
public class AsyncConfig {
    @Bean(name={"csvExportExecutor"})
    public Executor csvExportExecutor() {
        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
        executor.setCorePoolSize(5);
        executor.setMaxPoolSize(10);
        executor.setQueueCapacity(25);
        executor.setThreadNamePrefix("CsvExport-");
        executor.setRejectedExecutionHandler((r, executor1) -> System.err.println("CSV export task rejected due to thread pool saturation"));
        executor.initialize();
        return executor;
    }
}

package com.digicert.certificate.config;

import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.context.annotation.Configuration;

@Configuration
@ConfigurationProperties(prefix="csv.export")
public class CsvExportConfig {
    private boolean enabled = true;
    private int limit = 5000;
    private String localOutputPath = "./exports";
    private int batchSize = 1000;
    private int threshold = 1000;
    private int maxConcurrentCalls = 10;
    private int timeoutSeconds = 120;
    private S3Config s3 = new S3Config();

    public boolean isEnabled() {
        return this.enabled;
    }

    public void setEnabled(boolean enabled) {
        this.enabled = enabled;
    }

    public int getLimit() {
        return this.limit;
    }

    public void setLimit(int limit) {
        this.limit = limit;
    }

    public String getLocalOutputPath() {
        return this.localOutputPath;
    }

    public void setLocalOutputPath(String localOutputPath) {
        this.localOutputPath = localOutputPath;
    }

    public S3Config getS3() {
        return this.s3;
    }

    public void setS3(S3Config s3) {
        this.s3 = s3;
    }

    public int getBatchSize() {
        return this.batchSize;
    }

    public void setBatchSize(int batchSize) {
        this.batchSize = batchSize;
    }

    public int getThreshold() {
        return this.threshold;
    }

    public void setThreshold(int threshold) {
        this.threshold = threshold;
    }

    public int getMaxConcurrentCalls() {
        return this.maxConcurrentCalls;
    }

    public void setMaxConcurrentCalls(int maxConcurrentCalls) {
        this.maxConcurrentCalls = maxConcurrentCalls;
    }

    public int getTimeoutSeconds() {
        return this.timeoutSeconds;
    }

    public void setTimeoutSeconds(int timeoutSeconds) {
        this.timeoutSeconds = timeoutSeconds;
    }

    public static class S3Config {
        private boolean enabled = false;
        private String bucketName;
        private String region = "us-east-1";
        private String accessKeyId;
        private String secretAccessKey;
        private String folderPrefix = "certificate-exports";
        private boolean useIamRole = true;

        public boolean isEnabled() {
            return this.enabled;
        }

        public void setEnabled(boolean enabled) {
            this.enabled = enabled;
        }

        public String getBucketName() {
            return this.bucketName;
        }

        public void setBucketName(String bucketName) {
            this.bucketName = bucketName;
        }

        public String getRegion() {
            return this.region;
        }

        public void setRegion(String region) {
            this.region = region;
        }

        public String getAccessKeyId() {
            return this.accessKeyId;
        }

        public void setAccessKeyId(String accessKeyId) {
            this.accessKeyId = accessKeyId;
        }

        public String getSecretAccessKey() {
            return this.secretAccessKey;
        }

        public void setSecretAccessKey(String secretAccessKey) {
            this.secretAccessKey = secretAccessKey;
        }

        public String getFolderPrefix() {
            return this.folderPrefix;
        }

        public void setFolderPrefix(String folderPrefix) {
            this.folderPrefix = folderPrefix;
        }

        public boolean isUseIamRole() {
            return this.useIamRole;
        }

        public void setUseIamRole(boolean useIamRole) {
            this.useIamRole = useIamRole;
        }
    }
}

package com.digicert.certificate.config;

import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.context.annotation.Configuration;

@Configuration
@ConfigurationProperties(prefix="parallel.processing")
public class ParallelProcessingConfig {
    private boolean enabled = true;
