    private int batchSize = 1000;
    private int singleCallThreshold = 1000;
    private boolean partialFailureAllowed = true;
    private int timeoutSeconds = 90;

    public boolean isEnabled() {
        return this.enabled;
    }

    public void setEnabled(boolean enabled) {
        this.enabled = enabled;
    }

    public int getMaxConcurrentCalls() {
        return this.maxConcurrentCalls;
    }

    public void setMaxConcurrentCalls(int maxConcurrentCalls) {
        this.maxConcurrentCalls = maxConcurrentCalls;
    }

    public int getBatchSize() {
        return this.batchSize;
    }

    public void setBatchSize(int batchSize) {
        this.batchSize = batchSize;
    }

    public int getSingleCallThreshold() {
        return this.singleCallThreshold;
    }

    public void setSingleCallThreshold(int singleCallThreshold) {
        this.singleCallThreshold = singleCallThreshold;
    }

    public boolean isPartialFailureAllowed() {
        return this.partialFailureAllowed;
    }

    public void setPartialFailureAllowed(boolean partialFailureAllowed) {
        this.partialFailureAllowed = partialFailureAllowed;
    }

    public int getTimeoutSeconds() {
        return this.timeoutSeconds;
    }

    public void setTimeoutSeconds(int timeoutSeconds) {
        this.timeoutSeconds = timeoutSeconds;
    }

    public String toString() {
        return "ParallelProcessingConfig{enabled=" + this.enabled + ", maxConcurrentCalls=" + this.maxConcurrentCalls + ", batchSize=" + this.batchSize + ", singleCallThreshold=" + this.singleCallThreshold + ", partialFailureAllowed=" + this.partialFailureAllowed + ", timeoutSeconds=" + this.timeoutSeconds + "}";
    }
}

package com.digicert.certificate.config;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import software.amazon.awssdk.auth.credentials.DefaultCredentialsProvider;
import software.amazon.awssdk.auth.credentials.EnvironmentVariableCredentialsProvider;
import software.amazon.awssdk.regions.Region;
import software.amazon.awssdk.services.ssm.SsmClient;

@Configuration
public class ParameterStoreConfig {

    @Value("${aws.parameterstore.region:us-east-1}")
    private String region;

    @Value("${aws.parameterstore.use-iam-role:true}")
    private boolean useIamRole;

    @Bean
    public SsmClient ssmClient() {
        return SsmClient.builder()
                .region(Region.of(region))
                .credentialsProvider(useIamRole ? 
                    DefaultCredentialsProvider.create() : 
                    EnvironmentVariableCredentialsProvider.create())
                .build();
    }
}

package com.digicert.certificate.config;

import java.time.Duration;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.client.reactive.ClientHttpConnector;
import org.springframework.http.client.reactive.ReactorClientHttpConnector;
import org.springframework.web.reactive.function.client.ExchangeStrategies;
import org.springframework.web.reactive.function.client.WebClient;
import reactor.netty.http.client.HttpClient;
import reactor.netty.resources.ConnectionProvider;

@Configuration
public class RestClientConfig {
    @Value(value="${rest.api.base-url}")
    private String baseUrl;

    @Bean
    public WebClient webClient() {
        ConnectionProvider connectionProvider = ((ConnectionProvider.Builder)((ConnectionProvider.Builder)((ConnectionProvider.Builder)((ConnectionProvider.Builder)((ConnectionProvider.Builder)ConnectionProvider.builder((String)"custom").maxConnections(100)).maxIdleTime(Duration.ofSeconds(20L))).maxLifeTime(Duration.ofSeconds(60L))).pendingAcquireTimeout(Duration.ofSeconds(60L))).evictInBackground(Duration.ofSeconds(120L))).build();
        HttpClient httpClient = HttpClient.create((ConnectionProvider)connectionProvider).responseTimeout(Duration.ofMinutes(2L)).followRedirect(true);
        ExchangeStrategies strategies = ExchangeStrategies.builder().codecs(configurer -> configurer.defaultCodecs().maxInMemorySize(0x3200000)).build();
        return WebClient.builder().baseUrl(this.baseUrl).clientConnector((ClientHttpConnector)new ReactorClientHttpConnector(httpClient)).exchangeStrategies(strategies).build();
    }

    @Bean
    public Duration timeout() {
        return Duration.ofMinutes(2L);
    }
}

package com.digicert.certificate.config;

import com.digicert.certificate.exception.CertificateException;
import graphql.GraphQLError;
import graphql.GraphqlErrorBuilder;
import graphql.schema.DataFetchingEnvironment;
import java.util.HashMap;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.graphql.execution.DataFetcherExceptionResolverAdapter;

@Configuration
public class SimpleGraphQLConfig {
    @Bean
    public DataFetcherExceptionResolverAdapter exceptionResolver() {
        return new DataFetcherExceptionResolverAdapter(){

            protected GraphQLError resolveToSingleError(Throwable ex, DataFetchingEnvironment env) {
                if (ex instanceof CertificateException) {
                    CertificateException certException = (CertificateException)ex;
                    HashMap<String, Object> extensions = new HashMap<String, Object>();
                    extensions.put("errorCode", certException.getErrorCode());
                    extensions.put("errorType", certException.getErrorType());
                    return GraphqlErrorBuilder.newError((DataFetchingEnvironment)env).message(certException.getMessage(), new Object[0]).extensions(extensions).build();
                }
                HashMap<String, Object> extensions = new HashMap<String, Object>();
                extensions.put("errorCode", "INTERNAL_ERROR");
                extensions.put("errorType", "SYSTEM_ERROR");
                return GraphqlErrorBuilder.newError((DataFetchingEnvironment)env).message("An unexpected error occurred", new Object[0]).extensions(extensions).build();
            }
        };
    }
}

package com.digicert.certificate.config;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.web.embedded.tomcat.TomcatServletWebServerFactory;
import org.springframework.boot.web.server.WebServerFactoryCustomizer;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class TomcatConfig {

    @Value("${spring.mvc.async.request-timeout:180000}")
    private long asyncTimeout;

    @Bean
    public WebServerFactoryCustomizer<TomcatServletWebServerFactory> tomcatCustomizer() {
        return factory -> factory.addConnectorCustomizers(connector -> {
            connector.setAsyncTimeout(asyncTimeout);
        });
    }
}

package com.digicert.certificate.exception;

import com.digicert.certificate.exception.CertificateException;

