package com.digicert.certificate.model.entity;

public enum CertificateStatus {
    ISSUED("issued"),
    REVOKED("revoked"),
    EXPIRED("expired"),
    SUSPENDED("suspended");

    private final String value;

    private CertificateStatus(String value) {
        this.value = value;
    }

    public String getValue() {
        return this.value;
    }

    public static CertificateStatus fromValue(String value) {
        for (CertificateStatus status : CertificateStatus.values()) {
            if (!status.value.equals(value)) continue;
            return status;
        }
        throw new IllegalArgumentException("Unknown certificate status: " + value);
    }
}

