    @QueryMapping
    public Mono<CertificateSearchResult> certificateSearch(
            @Argument(value="offset") Integer offset, 
            @Argument(value="limit") Integer limit, 
            @Argument(value="sort") List<String> sort, 
            @Argument(value="accountId") String accountId, 
            @Argument(value="businessUnitId") String businessUnitId, 
            @Argument(value="businessUnitName") String businessUnitName, 
            @Argument(value="profileId") String profileId, 
            @Argument(value="seatId") String seatId, 
            @Argument(value="seatTypeId") String seatTypeId, 
            @Argument(value="serialNumber") String serialNumber, 
            @Argument(value="validFrom") String validFrom, 
            @Argument(value="validTo") String validTo, 
            @Argument(value="commonName") String commonName, 
            @Argument(value="aki") String aki, 
            @Argument(value="issuingCaId") String issuingCaId, 
            @Argument(value="issuingCaName") String issuingCaName, 
            @Argument(value="issuingCaSerialNumber") String issuingCaSerialNumber, 
            @Argument(value="status") String status, 
            @Argument(value="thumbprint") String thumbprint, 
            @Argument(value="enrollmentId") String enrollmentId, 
            @Argument(value="customAttributes") String customAttributes, 
            @Argument(value="certOwners") String certOwners, 
            @Argument(value="extendedKeyUsage") String extendedKeyUsage, 
            @Argument(value="icaId") String icaId, 
            @Argument(value="keyLength") Integer keyLength, 
            @Argument(value="signingAlgorithm") String signingAlgorithm, 
            @Argument(value="organizationName") String organizationName, 
            @Argument(value="caVendor") String caVendor, 
            @Argument(value="escrow") Boolean escrow, 
            @Argument(value="sans") String sans, 
            @Argument(value="source") String source,
            @Argument(value="certIssue") CertificateIssueType certIssue) {

        ServletRequestAttributes attrs = (ServletRequestAttributes)RequestContextHolder.getRequestAttributes();
        String cookie = null;
        String requestId = null;
        if (attrs != null) {
            HttpServletRequest request = attrs.getRequest();
            cookie = request.getHeader("Cookie");
            requestId = request.getHeader("Request-ID");
        }
        if (cookie == null || cookie.trim().isEmpty()) {
            logger.warn("Certificate search request rejected - missing Cookie header");
            throw AuthenticationException.missingCookie();
        }
        if (requestId == null || requestId.trim().isEmpty()) {
            logger.warn("Certificate search request rejected - missing Request-ID header");
            throw AuthenticationException.missingRequestId();
        }
        String finalCookie = cookie;
        String finalRequestId = requestId;

        logger.debug("GraphQL certificateSearch query - requestId: {}, offset: {}, limit: {}, accountId: {}, certIssue: {}, cookie: {}", 
                new Object[]{LogSanitizer.sanitize(finalRequestId), offset, limit, LogSanitizer.sanitize(accountId), certIssue, finalCookie != null ? "present" : "missing"});

        try {
            this.csvExportService.exportCertificatesAsync(finalRequestId, finalCookie, offset, limit, sort, accountId, 
                    businessUnitId, businessUnitName, profileId, seatId, seatTypeId, serialNumber, validFrom, validTo, 
                    commonName, aki, issuingCaId, issuingCaName, issuingCaSerialNumber, status, thumbprint, enrollmentId, 
                    customAttributes, certOwners, extendedKeyUsage, icaId, keyLength, signingAlgorithm, organizationName, 
                    caVendor, escrow, sans, source, certIssue);
            logger.debug("Triggered async CSV export for GraphQL request - requestId: {}", (Object)LogSanitizer.sanitize(finalRequestId));
        }
        catch (Exception e) {
            logger.error("Failed to trigger async CSV export - requestId: {}, error: {}", (Object)LogSanitizer.sanitize(finalRequestId), (Object)LogSanitizer.sanitize(e.getMessage()));
        }

        return this.certificateService.searchCertificates(
                finalRequestId, finalCookie, offset, limit, sort, accountId, businessUnitId, businessUnitName, 
                profileId, seatId, seatTypeId, serialNumber, validFrom, validTo, commonName, aki, issuingCaId, 
                issuingCaName, issuingCaSerialNumber, status, thumbprint, enrollmentId, customAttributes, 
                certOwners, extendedKeyUsage, icaId, keyLength, signingAlgorithm, organizationName, 
                caVendor, escrow, sans, source, certIssue)
                .doOnNext(result -> logger.debug("Returning {} certificates in GraphQL response - requestId: {}", 
                        (Object)(result.getItems() != null ? result.getItems().size() : 0), (Object)LogSanitizer.sanitize(finalRequestId)));
    }
}

