@Service
public class AsyncCsvExportService {
    private static final Logger logger = LoggerFactory.getLogger(AsyncCsvExportService.class);
    private final CertificateRestClient restClient;
    private final CsvExportConfig csvConfig;
    private volatile S3Client s3Client;

    public AsyncCsvExportService(CertificateRestClient restClient, CsvExportConfig csvConfig) {
        this.restClient = restClient;
        this.csvConfig = csvConfig;
        this.s3Client = this.initializeS3Client();
        try {
            Path exportPath = Paths.get(csvConfig.getLocalOutputPath(), new String[0]);
            if (!Files.exists(exportPath, new LinkOption[0])) {
                Files.createDirectories(exportPath, new FileAttribute[0]);
                logger.info("Created local export directory: {}", (Object)exportPath);
            }
        }
        catch (IOException e) {
            logger.error("Failed to create local export directory: {}", (Object)LogSanitizer.sanitize(e.getMessage()));
        }
    }

    private S3Client initializeS3Client() {
        if (!this.csvConfig.getS3().isEnabled()) {
            logger.info("S3 is disabled, CSV files will be saved locally only");
            return null;
        }
        try {
            AwsCredentialsProvider credentialsProvider;
            if (this.csvConfig.getS3().isUseIamRole()) {
                credentialsProvider = DefaultCredentialsProvider.create();
                logger.info("Using IAM role for S3 credentials");
            } else {
                String sessionToken = System.getenv("AWS_SESSION_TOKEN");
                if (sessionToken != null && !sessionToken.trim().isEmpty()) {
                    credentialsProvider = StaticCredentialsProvider.create((AwsCredentials)AwsSessionCredentials.create((String)this.csvConfig.getS3().getAccessKeyId(), (String)this.csvConfig.getS3().getSecretAccessKey(), (String)sessionToken));
                    logger.info("Using provided access keys with session token for S3 credentials");
                } else {
                    credentialsProvider = StaticCredentialsProvider.create((AwsCredentials)AwsBasicCredentials.create((String)this.csvConfig.getS3().getAccessKeyId(), (String)this.csvConfig.getS3().getSecretAccessKey()));
                    logger.info("Using provided access keys for S3 credentials");
                }
            }
            return (S3Client)((S3ClientBuilder)((S3ClientBuilder)S3Client.builder().region(Region.of((String)this.csvConfig.getS3().getRegion()))).credentialsProvider((AwsCredentialsProvider)credentialsProvider)).build();
        }
        catch (Exception e) {
            logger.error("Failed to initialize S3 client: {}", (Object)LogSanitizer.sanitize(e.getMessage()));
            return null;
        }
    }

    @Async(value="csvExportExecutor")
    public CompletableFuture<Void> exportCertificatesAsync(String requestId, String cookie, Integer offset, Integer limit, List<String> sort, String accountId, String businessUnitId, String businessUnitName, String profileId, String seatId, String seatTypeId, String serialNumber, String validFrom, String validTo, String commonName, String aki, String issuingCaId, String issuingCaName, String issuingCaSerialNumber, String status, String thumbprint, String enrollmentId, String customAttributes, String certOwners, String extendedKeyUsage, String icaId, Integer keyLength, String signingAlgorithm, String organizationName, String caVendor, Boolean escrow, String sans, String source, CertificateIssueType certIssue) {
        if (!this.csvConfig.isEnabled()) {
            logger.info("CSV export is disabled, skipping async export");
            return CompletableFuture.completedFuture(null);
        }
        String correlationId = this.generateCorrelationId();
        logger.info("Starting async CSV export [{}] with limit: {} - requestId: {}", new Object[]{correlationId, this.csvConfig.getLimit(), LogSanitizer.sanitize(requestId)});
        try {
            List<PublicCertificateDetails> allCertificates;
            int startOffset = offset != null ? offset : 0;
            int totalLimit = this.csvConfig.getLimit();
            if (totalLimit > this.csvConfig.getThreshold()) {
                logger.info("Using parallel batching for CSV export [{}] - total limit: {}, batch size: {} - requestId: {}", new Object[]{correlationId, totalLimit, this.csvConfig.getBatchSize(), LogSanitizer.sanitize(requestId)});
                allCertificates = this.executeParallelBatchesForCsv(correlationId, requestId, cookie, startOffset, totalLimit, sort, accountId, businessUnitId, businessUnitName, profileId, seatId, seatTypeId, serialNumber, validFrom, validTo, commonName, aki, issuingCaId, issuingCaName, issuingCaSerialNumber, status, thumbprint, enrollmentId, customAttributes, certOwners, extendedKeyUsage, icaId, keyLength, signingAlgorithm, organizationName, caVendor, escrow, sans, source, certIssue);
            } else {
                logger.info("Using single call for CSV export [{}] - limit: {} - requestId: {}", new Object[]{correlationId, totalLimit, LogSanitizer.sanitize(requestId)});
                allCertificates = this.executeSingleCallForCsv(requestId, cookie, startOffset, totalLimit, sort, accountId, businessUnitId, businessUnitName, profileId, seatId, seatTypeId, serialNumber, validFrom, validTo, commonName, aki, issuingCaId, issuingCaName, issuingCaSerialNumber, status, thumbprint, enrollmentId, customAttributes, certOwners, extendedKeyUsage, icaId, keyLength, signingAlgorithm, organizationName, caVendor, escrow, sans, source, certIssue);
            }
            if (allCertificates != null && !allCertificates.isEmpty()) {
                logger.info("Retrieved {} certificates for CSV export [{}]", (Object)allCertificates.size(), (Object)correlationId);
                String fileName = this.generateCsvFileName(requestId);
                String csvContent = this.generateCsvContent(allCertificates);
                this.saveLocalCsv(fileName, csvContent);
                if (this.csvConfig.getS3().isEnabled() && this.s3Client != null) {
                    this.uploadToS3(fileName, csvContent, requestId);
                }
                logger.info("CSV export completed successfully [{}] - File: {} with {} records", new Object[]{correlationId, fileName, allCertificates.size()});
            } else {
                logger.warn("No data retrieved for CSV export [{}]", (Object)correlationId);
            }
        }
        catch (Exception e) {
            logger.error("CSV export failed [{}]: {}", new Object[]{correlationId, LogSanitizer.sanitize(e.getMessage()), e});
        }
        return CompletableFuture.completedFuture(null);
    }

    private String generateCorrelationId() {
        return "CSV-" + System.currentTimeMillis() + "-" + Thread.currentThread().getId();
    }

