        boolean shouldUseSingleCall;
        logger.info("Certificate search request - requestId: {}, offset: {}, limit: {}, accountId: {}, certIssue: {}", 
                new Object[]{LogSanitizer.sanitize(requestId), offset, limit, LogSanitizer.sanitize(accountId), certIssue});

        boolean bl = shouldUseSingleCall = !this.parallelConfig.isEnabled() || limit == null || limit <= this.parallelConfig.getSingleCallThreshold();
        if (shouldUseSingleCall) {
            logger.debug("Using single call approach - requestId: {}, parallel processing disabled or small dataset (limit: {})", 
                    (Object)LogSanitizer.sanitize(requestId), (Object)limit);
            return this.makeSingleCall(requestId, cookie, offset, limit, sort, accountId, businessUnitId, 
                    businessUnitName, profileId, seatId, seatTypeId, serialNumber, validFrom, validTo, 
