                    enrollmentId, customAttributes, certOwners, extendedKeyUsage, icaId, keyLength, 
                    signingAlgorithm, organizationName, caVendor, escrow, sans, source, certIssue);
        }

        logger.info("Using standard parallel processing for large dataset - requestId: {}, limit: {}", 
                (Object)LogSanitizer.sanitize(requestId), (Object)limit);
        return this.makeParallelCalls(requestId, cookie, offset, limit, sort, accountId, businessUnitId, 
                businessUnitName, profileId, seatId, seatTypeId, serialNumber, validFrom, validTo, 
                commonName, aki, issuingCaId, issuingCaName, issuingCaSerialNumber, status, thumbprint, 
