package com.digicert.certificate.service;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.core.env.Environment;
import org.springframework.stereotype.Service;
import software.amazon.awssdk.services.ssm.SsmClient;
import software.amazon.awssdk.services.ssm.model.GetParameterRequest;
import software.amazon.awssdk.services.ssm.model.GetParameterResponse;
import software.amazon.awssdk.services.ssm.model.ParameterNotFoundException;
import software.amazon.awssdk.services.ssm.model.SsmException;

import jakarta.annotation.PostConstruct;
import java.time.LocalDateTime;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class ParameterStoreService {

    private static final Logger logger = LoggerFactory.getLogger(ParameterStoreService.class);

    @Autowired
    private SsmClient ssmClient;

    @Autowired
    private Environment environment;

    @Value("${aws.parameterstore.enabled:true}")
    private boolean parameterStoreEnabled;

    @Value("${aws.parameterstore.sample-key-name:/myapp/sample-key}")
    private String sampleKeyName;

    @Value("${aws.parameterstore.parameters:}")
    private String parametersToLoad;

    // Cache for storing parameter values
    private final Map<String, ParameterInfo> parameterCache = new ConcurrentHashMap<>();

    // Inner class to store parameter information
    public static class ParameterInfo {
        private final String value;
        private final LocalDateTime lastUpdated;
        private final String source; // "aws" or "fallback"
        private final String status; // "success", "fallback", "error"

        public ParameterInfo(String value, String source, String status) {
            this.value = value;
            this.lastUpdated = LocalDateTime.now();
            this.source = source;
            this.status = status;
        }

        public String getValue() { return value; }
        public LocalDateTime getLastUpdated() { return lastUpdated; }
        public String getSource() { return source; }
        public String getStatus() { return status; }
    }

    @PostConstruct
    public void init() {
        if (parameterStoreEnabled) {
            logger.info("Parameter Store service initialized. Sample key: {}", sampleKeyName);
            // Load batch parameters on startup
            loadBatchParameters();
            // Test sample parameter
            testParameterRetrieval();
        } else {
            logger.info("Parameter Store service is disabled");
        }
    }

    /**
     * Retrieves a parameter value from AWS Parameter Store
     * 
     * @param parameterName The name/path of the parameter in Parameter Store
     * @param withDecryption Whether to decrypt the parameter (for SecureString type)
     * @return Optional containing the parameter value if found, empty otherwise
     */
    public Optional<String> getParameter(String parameterName, boolean withDecryption) {
        if (!parameterStoreEnabled) {
            logger.warn("Parameter Store is disabled. Cannot retrieve parameter: {}", parameterName);
            return Optional.empty();
        }

        try {
            GetParameterRequest request = GetParameterRequest.builder()
                    .name(parameterName)
                    .withDecryption(withDecryption)
                    .build();

            GetParameterResponse response = ssmClient.getParameter(request);
            String value = response.parameter().value();

            logger.debug("Successfully retrieved parameter: {}", parameterName);
            return Optional.of(value);

        } catch (ParameterNotFoundException e) {
            logger.warn("Parameter not found: {}", parameterName);
            return Optional.empty();
        } catch (SsmException e) {
            logger.error("Error retrieving parameter {}: {}", parameterName, e.getMessage());
            return Optional.empty();
        }
    }

    /**
     * Retrieves a parameter value from AWS Parameter Store (non-encrypted)
     * 
     * @param parameterName The name/path of the parameter in Parameter Store
     * @return Optional containing the parameter value if found, empty otherwise
     */
    public Optional<String> getParameter(String parameterName) {
        return getParameter(parameterName, false);
    }

    /**
     * Retrieves a secure string parameter from AWS Parameter Store (encrypted)
     * 
     * @param parameterName The name/path of the parameter in Parameter Store
     * @return Optional containing the decrypted parameter value if found, empty otherwise
     */
    public Optional<String> getSecureParameter(String parameterName) {
        return getParameter(parameterName, true);
    }

    /**
     * Gets the sample key value for demonstration purposes
     * 
     * @return Optional containing the sample key value if found
     */
    public Optional<String> getSampleKey() {
        return getParameter(sampleKeyName);
    }

    /**
     * Loads all configured parameters from AWS Parameter Store into cache
     * Called on startup and can be triggered manually for refresh
     */
    public Map<String, ParameterInfo> loadBatchParameters() {
        if (!parameterStoreEnabled) {
            logger.warn("Parameter Store is disabled. Cannot load batch parameters.");
            return Collections.emptyMap();
        }

        if (parametersToLoad == null || parametersToLoad.trim().isEmpty()) {
            logger.info("No parameters configured for batch loading.");
            return Collections.emptyMap();
        }

        List<String> parameterNames = Arrays.asList(parametersToLoad.split(","));
        logger.info("Loading {} parameters from Parameter Store: {}", parameterNames.size(), parameterNames);

        Map<String, ParameterInfo> results = new HashMap<>();
        int successCount = 0;
        int fallbackCount = 0;
        int errorCount = 0;

        for (String parameterName : parameterNames) {
            String trimmedName = parameterName.trim();
            try {
                Optional<String> awsValue = getParameter(trimmedName, false);

                if (awsValue.isPresent()) {
                    // Successfully retrieved from AWS
                    ParameterInfo paramInfo = new ParameterInfo(awsValue.get(), "aws", "success");
                    parameterCache.put(trimmedName, paramInfo);
                    results.put(trimmedName, paramInfo);
                    successCount++;
                    logger.info("Loaded parameter '{}' from AWS Parameter Store", trimmedName);
                } else {
                    // Use fallback value from application.properties
                    String fallbackKey = "parameter.fallback." + trimmedName;
                    String fallbackValue = environment.getProperty(fallbackKey);

                    if (fallbackValue != null) {
                        ParameterInfo paramInfo = new ParameterInfo(fallbackValue, "fallback", "fallback");
                        parameterCache.put(trimmedName, paramInfo);
                        results.put(trimmedName, paramInfo);
                        fallbackCount++;
                        logger.warn("Parameter '{}' not found in AWS, using fallback value from {}", trimmedName, fallbackKey);
                    } else {
                        ParameterInfo paramInfo = new ParameterInfo("", "none", "error");
                        parameterCache.put(trimmedName, paramInfo);
                        results.put(trimmedName, paramInfo);
                        errorCount++;
                        logger.error("Parameter '{}' not found in AWS and no fallback value configured", trimmedName);
                    }
                }
            } catch (Exception e) {
                ParameterInfo paramInfo = new ParameterInfo("", "error", "error");
                parameterCache.put(trimmedName, paramInfo);
                results.put(trimmedName, paramInfo);
                errorCount++;
                logger.error("Error loading parameter '{}': {}", trimmedName, e.getMessage());
            }
        }

        logger.info("Batch parameter loading completed. Success: {}, Fallback: {}, Error: {}", 
                   successCount, fallbackCount, errorCount);
        return results;
    }

    /**
     * Gets a cached parameter value. Returns the cached value if available, 
     * otherwise attempts to load from AWS with fallback.
     * 
     * @param parameterName The name of the parameter
     * @return The parameter value or empty string if not found
     */
    public String getCachedParameter(String parameterName) {
        ParameterInfo cachedParam = parameterCache.get(parameterName);

        if (cachedParam != null) {
            return cachedParam.getValue();
        }

        // If not in cache, try to load it
        logger.debug("Parameter '{}' not found in cache, attempting to load", parameterName);
        Optional<String> value = getParameter(parameterName);

        if (value.isPresent()) {
            ParameterInfo paramInfo = new ParameterInfo(value.get(), "aws", "success");
            parameterCache.put(parameterName, paramInfo);
            return value.get();
        }

        // Try fallback
        String fallbackKey = "parameter.fallback." + parameterName;
        String fallbackValue = environment.getProperty(fallbackKey);
        if (fallbackValue != null) {
            ParameterInfo paramInfo = new ParameterInfo(fallbackValue, "fallback", "fallback");
            parameterCache.put(parameterName, paramInfo);
            return fallbackValue;
        }

        return "";
    }

    /**
     * Gets information about a cached parameter including metadata
     * 
     * @param parameterName The name of the parameter
     * @return ParameterInfo object with value and metadata
     */
    public ParameterInfo getCachedParameterInfo(String parameterName) {
        return parameterCache.get(parameterName);
    }

    /**
     * Gets all cached parameters
     * 
     * @return Map of all cached parameters with their info
     */
    public Map<String, ParameterInfo> getAllCachedParameters() {
        return new HashMap<>(parameterCache);
    }

    /**
     * Refreshes all configured parameters from AWS Parameter Store
     * 
     * @return Map of refreshed parameters with their info
     */
    public Map<String, ParameterInfo> refreshAllParameters() {
        logger.info("Refreshing all configured parameters from AWS Parameter Store");
        return loadBatchParameters();
    }

    /**
     * Clears the parameter cache
     */
    public void clearCache() {
        parameterCache.clear();
        logger.info("Parameter cache cleared");
    }

    /**
     * Test method to verify Parameter Store connectivity
     */
    private void testParameterRetrieval() {
        try {
            Optional<String> sampleValue = getSampleKey();
            if (sampleValue.isPresent()) {
                logger.info("Successfully connected to Parameter Store. Sample key value retrieved.");
            } else {
                logger.warn("Parameter Store connection successful but sample key '{}' not found", sampleKeyName);
            }
        } catch (Exception e) {
            logger.error("Failed to test Parameter Store connectivity: {}", e.getMessage());
        }
    }
}

package com.digicert.certificate.util;

/**
 * Utility class for sanitizing inputs before logging to prevent CRLF injection attacks.
 */
public class LogSanitizer {

    /**
     * Sanitizes input strings for safe logging by removing or replacing potentially dangerous characters.
     * This method removes carriage returns and line feeds to prevent CRLF injection attacks.
     *
     * @param input The input string to sanitize, may be null
     * @return A sanitized version of the input string, or null if input was null
     */
    public static String sanitize(String input) {
        if (input == null) {
            return null;
        }

        // Remove carriage returns and line feeds to prevent CRLF injection
        return input.replace("\r", "").replace("\n", "");
    }

    /**
     * Sanitizes an object for safe logging.
     * If the object is a String, it sanitizes it; otherwise, it returns the object as is.
     *
     * @param obj The object to sanitize
     * @return A sanitized version of the object if it's a String, otherwise the original object
     */
    public static Object sanitize(Object obj) {
        if (obj instanceof String) {
            return sanitize((String) obj);
        }
        return obj;
    }
}

