class CertificateRestClientTest extends BaseUnitTest {

    private static ClientResponse response(HttpStatus status, MediaType contentType, String body) {
        DataBuffer buffer = new DefaultDataBufferFactory().wrap(body.getBytes(StandardCharsets.UTF_8));
        return ClientResponse.create(status)
                .header(HttpHeaders.CONTENT_TYPE, contentType.toString())
                .body(Flux.just(buffer))
