            String json = """
                    {"items":[{"id":"1","serial_number":"SN1","common_name":"example.com"}],"total":1,"limit":5,"offset":0}
                    """;
            return Mono.just(response(HttpStatus.OK, MediaType.APPLICATION_JSON, json));
        };

        WebClient wc = WebClient.builder()
                .baseUrl("http://localhost:8080")
                .exchangeFunction(exchange)
                .build();

        CertificateRestClient client = new CertificateRestClient(wc, "http://localhost:8080");

        Mono<CertificateSearchResult> result = client.searchCertificates(
                "req-123",
                "dcone.access.token=test-token; path=/",
                0,
                5,
                List.of("validTo:desc", "commonName:asc"),
