                null,
                null,
                null,
                false,
                null,
                "graphql",
                CertificateIssueType.IS_SAN_INCLUDE_CN
        );

        StepVerifier.create(result)
                .expectNextMatches(r -> r.getTotal() == 1 && r.getItems() != null && r.getItems().size() == 1)
                .verifyComplete();

        ClientRequest req = captured.get();
        assertThat(req).isNotNull();
        assertThat(req.headers().getFirst("Accept")).contains("application/json");
        assertThat(req.headers().getFirst("Cookie")).contains("dcone.access.token");

        URI uri = req.url();
        assertThat(uri.getPath()).endsWith("/certificate-search");
        var params = UriComponentsBuilder.fromUri(uri).build().getQueryParams();
        assertThat(params.getFirst("offset")).isEqualTo("0");
        assertThat(params.getFirst("limit")).isEqualTo("5");
        assertThat(params.getFirst("status")).isEqualTo("issued"); // lowercased
        assertThat(params.getFirst("extendedKeyUsage")).isEqualTo("eku"); // trimmed
