package com.digicert.certificate.config;

import com.digicert.certificate.BaseUnitTest;
import com.digicert.certificate.exception.CertificateException;
import graphql.GraphQLError;
import graphql.schema.DataFetchingEnvironment;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.springframework.graphql.execution.DataFetcherExceptionResolverAdapter;

import java.lang.reflect.Method;
import java.util.Map;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.Answers.RETURNS_DEEP_STUBS;
import static org.mockito.Mockito.mock;

class SimpleGraphQLConfigTest extends BaseUnitTest {

    @Test
    @DisplayName("exceptionResolver should map CertificateException to GraphQL error extensions")
    void exceptionResolverShouldMapCertificateException() throws Exception {
        SimpleGraphQLConfig config = new SimpleGraphQLConfig();
        DataFetcherExceptionResolverAdapter resolver = config.exceptionResolver();

        DataFetchingEnvironment env = mock(DataFetchingEnvironment.class, RETURNS_DEEP_STUBS);
        CertificateException ex = new CertificateException("bad cookie", "MISSING_COOKIE", "AUTHENTICATION_ERROR");

        Method m = resolver.getClass().getDeclaredMethod("resolveToSingleError", Throwable.class, DataFetchingEnvironment.class);
        m.setAccessible(true);
        GraphQLError err = (GraphQLError) m.invoke(resolver, ex, env);

        assertThat(err.getMessage()).isEqualTo("bad cookie");
        assertThat(err.getExtensions()).containsEntry("errorCode", "MISSING_COOKIE");
        assertThat(err.getExtensions()).containsEntry("errorType", "AUTHENTICATION_ERROR");
    }

    @Test
    @DisplayName("exceptionResolver should map unknown exceptions to INTERNAL_ERROR/SYSTEM_ERROR")
    void exceptionResolverShouldMapUnknownException() throws Exception {
        SimpleGraphQLConfig config = new SimpleGraphQLConfig();
        DataFetcherExceptionResolverAdapter resolver = config.exceptionResolver();

        DataFetchingEnvironment env = mock(DataFetchingEnvironment.class, RETURNS_DEEP_STUBS);
        RuntimeException ex = new RuntimeException("boom");

        Method m = resolver.getClass().getDeclaredMethod("resolveToSingleError", Throwable.class, DataFetchingEnvironment.class);
        m.setAccessible(true);
        GraphQLError err = (GraphQLError) m.invoke(resolver, ex, env);

        assertThat(err.getMessage()).isEqualTo("An unexpected error occurred");
        Map<String, Object> extensions = err.getExtensions();
        assertThat(extensions).containsEntry("errorCode", "INTERNAL_ERROR");
        assertThat(extensions).containsEntry("errorType", "SYSTEM_ERROR");
    }
}

package com.digicert.certificate.exception;

import com.digicert.certificate.BaseUnitTest;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.DisplayName;

import static org.assertj.core.api.Assertions.assertThat;

@DisplayName("Exception Classes Unit Tests")
class ExceptionClassesTest extends BaseUnitTest {

    @Test
    @DisplayName("Should create AuthenticationException with message and error code")
    void shouldCreateAuthenticationExceptionWithMessageAndErrorCode() {
        // Arrange
        String message = "Test authentication error";
        String errorCode = "TEST_AUTH_ERROR";

        // Act
        AuthenticationException exception = new AuthenticationException(message, errorCode);

        // Assert
        assertThat(exception.getMessage()).isEqualTo(message);
        assertThat(exception.getErrorCode()).isEqualTo(errorCode);
        assertThat(exception.getErrorType()).isEqualTo(AuthenticationException.ERROR_TYPE);
        assertThat(exception.getCause()).isNull();
    }

    @Test
    @DisplayName("Should create AuthenticationException with message, error code, and cause")
    void shouldCreateAuthenticationExceptionWithMessageErrorCodeAndCause() {
        // Arrange
        String message = "Test authentication error with cause";
        String errorCode = "TEST_AUTH_ERROR_CAUSE";
        RuntimeException cause = new RuntimeException("Root cause");

        // Act
        AuthenticationException exception = new AuthenticationException(message, errorCode, cause);

        // Assert
        assertThat(exception.getMessage()).isEqualTo(message);
        assertThat(exception.getErrorCode()).isEqualTo(errorCode);
        assertThat(exception.getErrorType()).isEqualTo(AuthenticationException.ERROR_TYPE);
        assertThat(exception.getCause()).isEqualTo(cause);
    }

    @Test
    @DisplayName("Should create missing cookie exception correctly")
    void shouldCreateMissingCookieExceptionCorrectly() {
        // Act
        AuthenticationException exception = AuthenticationException.missingCookie();

        // Assert
        assertThat(exception.getMessage()).isEqualTo("cookie is a mandatory header");
        assertThat(exception.getErrorCode()).isEqualTo(AuthenticationException.MISSING_COOKIE_CODE);
        assertThat(exception.getErrorType()).isEqualTo(AuthenticationException.ERROR_TYPE);
    }

    @Test
    @DisplayName("Should create expired cookies exception correctly")
    void shouldCreateExpiredCookiesExceptionCorrectly() {
        // Act
        AuthenticationException exception = AuthenticationException.expiredCookies();

        // Assert
        assertThat(exception.getMessage()).isEqualTo("Authentication failed - cookies expired");
        assertThat(exception.getErrorCode()).isEqualTo(AuthenticationException.EXPIRED_COOKIES_CODE);
        assertThat(exception.getErrorType()).isEqualTo(AuthenticationException.ERROR_TYPE);
    }

    @Test
    @DisplayName("Should create missing request ID exception correctly")
    void shouldCreateMissingRequestIdExceptionCorrectly() {
        // Act
        AuthenticationException exception = AuthenticationException.missingRequestId();

        // Assert
        assertThat(exception.getMessage()).isEqualTo("request id is missing");
        assertThat(exception.getErrorCode()).isEqualTo(AuthenticationException.MISSING_REQUEST_ID_CODE);
        assertThat(exception.getErrorType()).isEqualTo(AuthenticationException.ERROR_TYPE);
    }

    @Test
    @DisplayName("Should verify all error code constants")
    void shouldVerifyAllErrorCodeConstants() {
        // Assert
        assertThat(AuthenticationException.MISSING_COOKIE_CODE).isEqualTo("MISSING_COOKIE");
        assertThat(AuthenticationException.EXPIRED_COOKIES_CODE).isEqualTo("EXPIRED_COOKIES");
        assertThat(AuthenticationException.MISSING_REQUEST_ID_CODE).isEqualTo("MISSING_REQUEST_ID");
        assertThat(AuthenticationException.ERROR_TYPE).isEqualTo("AUTHENTICATION_ERROR");
    }

    @Test
    @DisplayName("Should create ApiException correctly")
    void shouldCreateApiExceptionCorrectly() {
        // Arrange
        String message = "API error occurred";
        int statusCode = 400;

        // Act
        ApiException exception = ApiException.badRequest(message, statusCode);

        // Assert
        assertThat(exception.getMessage()).isEqualTo(message);
        assertThat(exception.getStatusCode()).isEqualTo(statusCode);
    }

    @Test
    @DisplayName("Should create API error exception correctly")
    void shouldCreateApiErrorExceptionCorrectly() {
        // Arrange
        String message = "Internal API error";
        int statusCode = 500;

        // Act
        ApiException exception = ApiException.apiError(message, statusCode);

        // Assert
        assertThat(exception.getMessage()).isEqualTo(message);
        assertThat(exception.getStatusCode()).isEqualTo(statusCode);
    }

    @Test
    @DisplayName("Should create SystemException correctly")
    void shouldCreateSystemExceptionCorrectly() {
        // Arrange
        String message = "System error occurred";
        RuntimeException cause = new RuntimeException("Root cause");

        // Act
        SystemException exception = SystemException.internalError(message, cause);

        // Assert
        assertThat(exception.getMessage()).isEqualTo(message);
        assertThat(exception.getCause()).isEqualTo(cause);
    }

    @Test
    @DisplayName("Should inherit from CertificateException")
    void shouldInheritFromCertificateException() {
        // Act
        AuthenticationException authException = AuthenticationException.missingCookie();
        ApiException apiException = ApiException.badRequest("Bad request", 400);
        SystemException systemException = SystemException.internalError("Internal error", null);

        // Assert
        assertThat(authException).isInstanceOf(CertificateException.class);
        assertThat(apiException).isInstanceOf(CertificateException.class);
        assertThat(systemException).isInstanceOf(CertificateException.class);
    }

    @Test
    @DisplayName("Should be runtime exceptions")
    void shouldBeRuntimeExceptions() {
        // Act
        AuthenticationException authException = AuthenticationException.missingCookie();
        ApiException apiException = ApiException.badRequest("Bad request", 400);
        SystemException systemException = SystemException.internalError("Internal error", null);

        // Assert
        assertThat(authException).isInstanceOf(RuntimeException.class);
        assertThat(apiException).isInstanceOf(RuntimeException.class);
        assertThat(systemException).isInstanceOf(RuntimeException.class);
    }

    @Test
    @DisplayName("Should handle null values in exception creation")
    void shouldHandleNullValuesInExceptionCreation() {
        // Act & Assert - Should not throw exceptions
        AuthenticationException authException = new AuthenticationException(null, null);
        assertThat(authException.getMessage()).isNull();
        assertThat(authException.getErrorCode()).isNull();

        AuthenticationException authExceptionWithCause = new AuthenticationException(null, null, null);
        assertThat(authExceptionWithCause.getMessage()).isNull();
        assertThat(authExceptionWithCause.getErrorCode()).isNull();
        assertThat(authExceptionWithCause.getCause()).isNull();
    }

    @Test
    @DisplayName("Should handle empty strings in exception creation")
    void shouldHandleEmptyStringsInExceptionCreation() {
        // Act
        AuthenticationException authException = new AuthenticationException("", "");

        // Assert
        assertThat(authException.getMessage()).isEmpty();
        assertThat(authException.getErrorCode()).isEmpty();
        assertThat(authException.getErrorType()).isEqualTo(AuthenticationException.ERROR_TYPE);
    }
}

