        f.setAccessible(true);
        f.set(target, value);
    }

    private static Object invoke(Object target, String methodName, Class<?>[] paramTypes, Object... args) throws Exception {
        Method m = target.getClass().getDeclaredMethod(methodName, paramTypes);
        m.setAccessible(true);
        return m.invoke(target, args);
    }

    @Test
    @DisplayName("exportCertificatesAsync should write a local CSV (single call path)")
    void exportCertificatesAsyncShouldWriteLocalCsvSingleCall() throws Exception {
        CsvExportConfig cfg = new CsvExportConfig();
        cfg.setEnabled(true);
        cfg.setLocalOutputPath(tempDir.toString());
        cfg.setLimit(2);
        cfg.setThreshold(10);
        cfg.setBatchSize(2);
        cfg.setTimeoutSeconds(5);

        AsyncCsvExportService svc = new AsyncCsvExportService(restClient, cfg);

        PublicCertificateDetails cert = TestDataFactory.createTestCertificate("1", "name,with,comma");
        cert.setSerialNumber("SN\"1\"");
        cert.setAttributes("{\"san\":{\"dns_name\":[\"a.com\",\"b.com\"]}}");

        CertificateSearchResult searchResult = new CertificateSearchResult(List.of(cert), 1, 2, 0);
        when(restClient.searchCertificates(
                anyString(), anyString(), anyInt(), anyInt(), any(), any(),
                any(), any(), any(), any(), any(), any(), any(), any(), any(),
                any(), any(), any(), any(), any(), any(), any(), any(), any(),
                any(), any(), any(), any(), any(), any(), any(), any(), any(), any()
        )).thenReturn(Mono.just(searchResult));

        CompletableFuture<Void> future = svc.exportCertificatesAsync(
                "req123",
                TestDataFactory.createTestCookie(),
                0,
                2,
                null,
                "acc123",
                null, null, null, null, null, null, null, null, null,
                null, null, null, null, "issued", null, null, null, null, null,
                null, 2048, null, null, null, null, null, null,
                CertificateIssueType.IS_CERT_VALID
        );
        future.get(2, TimeUnit.SECONDS);

        Path csv = tempDir.resolve("req123.csv");
        assertThat(Files.exists(csv)).isTrue();

        String content = Files.readString(csv);
        assertThat(content).contains("Serial Number,Common Name,Thumbprint");
        // Escaping: quotes doubled and value wrapped in quotes
        assertThat(content).contains("\"SN\"\"1\"\"\"");
        assertThat(content).contains("\"name,with,comma\"");
        // SANs extracted from attributes
        assertThat(content).contains("\"a.com,b.com\"");
    }

