class ParameterStoreServiceTest extends BaseUnitTest {

    @Mock
    private SsmClient ssmClient;

    @Mock
    private Environment environment;

    private ParameterStoreService parameterStoreService;

    @BeforeEach
    void setUp() {
        // Create service with mocked dependencies
        parameterStoreService = new ParameterStoreService();

        // Use reflection to inject mocked dependencies
        try {
            java.lang.reflect.Field ssmClientField = ParameterStoreService.class.getDeclaredField("ssmClient");
            ssmClientField.setAccessible(true);
            ssmClientField.set(parameterStoreService, ssmClient);

            java.lang.reflect.Field environmentField = ParameterStoreService.class.getDeclaredField("environment");
            environmentField.setAccessible(true);
            environmentField.set(parameterStoreService, environment);

            // Set parameterStoreEnabled to true for testing
            java.lang.reflect.Field enabledField = ParameterStoreService.class.getDeclaredField("parameterStoreEnabled");
            enabledField.setAccessible(true);
            enabledField.set(parameterStoreService, true);

            // Set sample key name for testing
            java.lang.reflect.Field sampleKeyField = ParameterStoreService.class.getDeclaredField("sampleKeyName");
            sampleKeyField.setAccessible(true);
            sampleKeyField.set(parameterStoreService, "/test/myapp/sample-key");

            // Set parameters to load for testing
            java.lang.reflect.Field parametersField = ParameterStoreService.class.getDeclaredField("parametersToLoad");
            parametersField.setAccessible(true);
            parametersField.set(parameterStoreService, "/test/myapp/param1,/test/myapp/param2");

        } catch (Exception e) {
            throw new RuntimeException("Failed to inject dependencies", e);
        }
    }

