        // Act
        Map<String, ParameterStoreService.ParameterInfo> result = parameterStoreService.loadBatchParameters();

        // Assert
        assertThat(result).hasSize(2);
        assertThat(result.get("/test/myapp/param1").getValue()).isEqualTo("value1");
