package com.digicert.certificate.util;

import com.digicert.certificate.BaseUnitTest;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.ValueSource;
import org.junit.jupiter.params.provider.NullSource;

import static org.assertj.core.api.Assertions.assertThat;

@DisplayName("LogSanitizer Unit Tests")
class LogSanitizerTest extends BaseUnitTest {

    @Test
    @DisplayName("Should return null when input is null")
    void shouldReturnNullWhenInputIsNull() {
        // Act
        String result = LogSanitizer.sanitize((String) null);

        // Assert
        assertThat(result).isNull();
    }

    @Test
    @DisplayName("Should return same string when no dangerous characters present")
    void shouldReturnSameStringWhenNoDangerousCharactersPresent() {
        // Arrange
        String input = "This is a safe log message";

        // Act
        String result = LogSanitizer.sanitize(input);

        // Assert
        assertThat(result).isEqualTo(input);
    }

    @Test
    @DisplayName("Should remove carriage return characters")
    void shouldRemoveCarriageReturnCharacters() {
        // Arrange
        String input = "Log message\rwith carriage return";

        // Act
        String result = LogSanitizer.sanitize(input);

        // Assert
        assertThat(result).isEqualTo("Log messagewith carriage return");
        assertThat(result).doesNotContain("\r");
    }

    @Test
    @DisplayName("Should remove line feed characters")
    void shouldRemoveLineFeedCharacters() {
        // Arrange
        String input = "Log message\nwith line feed";

        // Act
        String result = LogSanitizer.sanitize(input);

        // Assert
        assertThat(result).isEqualTo("Log messagewith line feed");
        assertThat(result).doesNotContain("\n");
    }

    @Test
    @DisplayName("Should remove both carriage return and line feed characters")
    void shouldRemoveBothCarriageReturnAndLineFeedCharacters() {
        // Arrange
        String input = "Log message\r\nwith CRLF";

        // Act
        String result = LogSanitizer.sanitize(input);

        // Assert
        assertThat(result).isEqualTo("Log messagewith CRLF");
        assertThat(result).doesNotContain("\r");
        assertThat(result).doesNotContain("\n");
    }

    @Test
    @DisplayName("Should handle multiple CRLF sequences")
    void shouldHandleMultipleCrlfSequences() {
        // Arrange
        String input = "First line\r\nSecond line\r\nThird line\n\rFourth line";

        // Act
        String result = LogSanitizer.sanitize(input);

        // Assert
        assertThat(result).isEqualTo("First lineSecond lineThird lineFourth line");
        assertThat(result).doesNotContain("\r");
        assertThat(result).doesNotContain("\n");
    }

    @Test
    @DisplayName("Should handle empty string")
    void shouldHandleEmptyString() {
        // Arrange
        String input = "";

        // Act
        String result = LogSanitizer.sanitize(input);

        // Assert
        assertThat(result).isEmpty();
    }

    @Test
    @DisplayName("Should handle string with only CRLF characters")
    void shouldHandleStringWithOnlyCrlfCharacters() {
        // Arrange
        String input = "\r\n\r\n\r\n";

        // Act
        String result = LogSanitizer.sanitize(input);

        // Assert
        assertThat(result).isEmpty();
    }

    @ParameterizedTest
    @ValueSource(strings = {
            "Normal text",
            "Text with spaces and numbers 123",
            "Text!@#$%^&*()with special chars",
            "Unicode text: 你好世界",
            "Tab\tcharacter included"
    })
    @DisplayName("Should preserve safe characters")
    void shouldPreserveSafeCharacters(String input) {
        // Act
        String result = LogSanitizer.sanitize(input);

        // Assert
        assertThat(result).isEqualTo(input);
    }

    @Test
    @DisplayName("Should handle object sanitization with string input")
    void shouldHandleObjectSanitizationWithStringInput() {
        // Arrange
        Object input = "String with\r\nCRLF characters";

        // Act
        Object result = LogSanitizer.sanitize(input);

        // Assert
        assertThat(result).isInstanceOf(String.class);
        assertThat((String) result).isEqualTo("String withCRLF characters");
    }

    @Test
    @DisplayName("Should handle object sanitization with non-string input")
    void shouldHandleObjectSanitizationWithNonStringInput() {
        // Arrange
        Integer input = 12345;

        // Act
        Object result = LogSanitizer.sanitize(input);

        // Assert
        assertThat(result).isEqualTo(input);
        assertThat(result).isInstanceOf(Integer.class);
    }

    @Test
    @DisplayName("Should handle object sanitization with null input")
    void shouldHandleObjectSanitizationWithNullInput() {
        // Act
        Object result = LogSanitizer.sanitize((Object) null);

        // Assert
        assertThat(result).isNull();
    }

    @Test
    @DisplayName("Should handle complex CRLF injection attempt")
    void shouldHandleComplexCrlfInjectionAttempt() {
        // Arrange - Simulating a potential CRLF injection attack
        String input = "username=admin\r\nSet-Cookie: sessionId=hijacked\r\nContent-Length: 0\r\n\r\nHTTP/1.1 200 OK";

        // Act
        String result = LogSanitizer.sanitize(input);

        // Assert
        String expected = "username=adminSet-Cookie: sessionId=hijackedContent-Length: 0HTTP/1.1 200 OK";
        assertThat(result).isEqualTo(expected);
        assertThat(result).doesNotContain("\r");
        assertThat(result).doesNotContain("\n");
    }

    @Test
    @DisplayName("Should handle large strings efficiently")
    void shouldHandleLargeStringsEfficiently() {
        // Arrange
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 10000; i++) {
            sb.append("Safe text ").append(i);
            if (i % 100 == 0) {
                sb.append("\r\n");
            }
        }
        String input = sb.toString();

        // Act
        long startTime = System.currentTimeMillis();
        String result = LogSanitizer.sanitize(input);
        long endTime = System.currentTimeMillis();

        // Assert
        assertThat(result).doesNotContain("\r");
        assertThat(result).doesNotContain("\n");
        assertThat(endTime - startTime).isLessThan(100); // Should complete quickly
    }

    @Test
    @DisplayName("Should preserve whitespace other than CRLF")
    void shouldPreserveWhitespaceOtherThanCrlf() {
        // Arrange
        String input = " \t Spaced text \t with tabs and spaces \t ";

        // Act
        String result = LogSanitizer.sanitize(input);

        // Assert
        assertThat(result).isEqualTo(input);
    }

    @Test
    @DisplayName("Should handle consecutive CRLF characters")
    void shouldHandleConsecutiveCrlfCharacters() {
        // Arrange
        String input = "text\r\r\r\n\n\nmore text";

        // Act
        String result = LogSanitizer.sanitize(input);

        // Assert
        assertThat(result).isEqualTo("textmore text");
    }
}
